import{_ as e,o as s,c as a,Q as n}from"./chunks/framework.b6910bb2.js";const l="/vitePress-blob/assets/18.84058b1a.png",o="/vitePress-blob/assets/23.c3f7cd8c.png",p="/vitePress-blob/assets/25.b2aee701.png",t="/vitePress-blob/assets/24.ee6c91cc.png",i="/vitePress-blob/assets/26.1018dc1c.png",r="/vitePress-blob/assets/27.af8a3392.png",c="/vitePress-blob/assets/28.2ec3a182.png",d="/vitePress-blob/assets/29.8153324c.png",h="/vitePress-blob/assets/30.1bffaf1e.png",u="/vitePress-blob/assets/19.02dcdda6.png",g="/vitePress-blob/assets/20.cb0a263a.png",b="/vitePress-blob/assets/21.ae7c11ab.png",m="/vitePress-blob/assets/22.8421793f.png",w=JSON.parse('{"title":"Claude Code 中的 SubAgent","description":"","frontmatter":{},"headers":[],"relativePath":"guide/ai/Claude Code 中的 SubAgent.md","filePath":"guide/ai/Claude Code 中的 SubAgent.md","lastUpdated":1773984458000}'),y={name:"guide/ai/Claude Code 中的 SubAgent.md"},A=n(`<h1 id="claude-code-中的-subagent" tabindex="-1">Claude Code 中的 SubAgent <a class="header-anchor" href="#claude-code-中的-subagent" aria-label="Permalink to &quot;Claude Code 中的 SubAgent&quot;">​</a></h1><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>上一讲我们介绍了 Claude Code 的记忆系统，了解了如何解决 Claude 的失忆症问题以及如何写好 CLAUDE.md。</p><p>本讲我们主要介绍 Claude Code 中的 SubAgent.</p><h2 id="为什么要有-sub-agents" tabindex="-1">为什么要有 Sub-Agents？ <a class="header-anchor" href="#为什么要有-sub-agents" aria-label="Permalink to &quot;为什么要有 Sub-Agents？&quot;">​</a></h2><p>SubAgent 主要解决单一 Agent 在<strong>上下文、权限、职责</strong>无法无限膨胀的问题。</p><p>例如某天，你让 Claude Code 帮你跑一个测试套件，结果输出了 500 行日志；然后你想让它分析一下代码结构，又输出了 200 行；接着你想让它改一个 bug，丢给它上千行的日志信息，你的对话上下文已经被各种“中间过程”塞满了，真正重要的信息被淹没在茫茫的输出海洋里。</p><p>此时，如果你觉得 Claude Code 越用越“健忘”，并不是模型退化了，而是你的对话上下文，已经被一次次中间过程污染了，稀释了真正重要的信息，这正是子代理要解决的核心问题。</p><p>而 SubAgent 的出现，可以做到隔离上下文、权限、职责，从而避免单一 Agent 在上下文过渡膨胀，导致无法聚焦核心任务。</p><p>基于这个思想，开源社区也出现了三省六部制多 Agent 设计理念。</p><p>例如👉 : <a href="https://github.com/cft0808/edict" target="_blank" rel="noreferrer">三省六部制多 Agent 设计理念</a></p><h2 id="什么是子代理" tabindex="-1">什么是子代理？ <a class="header-anchor" href="#什么是子代理" aria-label="Permalink to &quot;什么是子代理？&quot;">​</a></h2><p>子代理相当于一个“专职小助手”，带着自己的权限、上下文窗口，去完成某一类任务，然后把“结果摘要”带回来给主 Agent。</p><p>子 Agent 核心价值有三点:</p><ul><li>隔离</li><li>约束</li><li>负责</li></ul><h3 id="隔离-解决上下文污染问题" tabindex="-1">隔离 - 解决上下文污染问题 <a class="header-anchor" href="#隔离-解决上下文污染问题" aria-label="Permalink to &quot;隔离 - 解决上下文污染问题&quot;">​</a></h3><p>主要解决单一 Agent 在上下文无限膨胀，稀释 Agent 注意力的问题。</p><p>例如，让 Agent 分析了错误日志，又让它跑测试用例，中间过程会输出大量日志信息，这些日志信息会残留在上下文窗口中，稀释了 Agent 的注意力，导致无法聚焦后续的核心任务。</p><p>而 SubAgent 可以做到隔离上下文，将分析后的结果带回给主 Agent，让主 Agent 做的更少，做的更对。</p><h3 id="约束-权限隔离问题" tabindex="-1">约束 - 权限隔离问题 <a class="header-anchor" href="#约束-权限隔离问题" aria-label="Permalink to &quot;约束 - 权限隔离问题&quot;">​</a></h3><p>当你让 Claude Code 进行 code Review 时，Claude Code 可能会修改代码，而你只是想让他进行代码 Review，而不是修改代码。 而 SubAgent 可以做到约束权限，只让 Agent 进行代码 Review 时只有 Read （读）, Grep（搜索）, Glob（匹配文件） 权限，而不是有修改代码的权限（Write）。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">allowed-tools: Read, Grep, Glob</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">allowed-tools: Read, Grep, Glob</span></span></code></pre></div><h3 id="复用-避免重复工作" tabindex="-1">复用 - 避免重复工作 <a class="header-anchor" href="#复用-避免重复工作" aria-label="Permalink to &quot;复用 - 避免重复工作&quot;">​</a></h3><p>SubAgent 可以沉淀成一个文件，纳入版本控制，团队共享，避免重复开发。</p><h2 id="什么时候该用子代理" tabindex="-1">什么时候该用子代理？ <a class="header-anchor" href="#什么时候该用子代理" aria-label="Permalink to &quot;什么时候该用子代理？&quot;">​</a></h2><h3 id="处理高噪声的任务-例如跑测试用例、分析错误日志" tabindex="-1">处理高噪声的任务 - 例如跑测试用例、分析错误日志 <a class="header-anchor" href="#处理高噪声的任务-例如跑测试用例、分析错误日志" aria-label="Permalink to &quot;处理高噪声的任务 - 例如跑测试用例、分析错误日志&quot;">​</a></h3><p>当任务的输出结果包含大量噪声时，使用子代理可以避免主 Agent 被噪声淹没，从而更好地聚焦核心任务。</p><h3 id="有权限隔离的需求-例如代码审查" tabindex="-1">有权限隔离的需求 - 例如代码审查 <a class="header-anchor" href="#有权限隔离的需求-例如代码审查" aria-label="Permalink to &quot;有权限隔离的需求 - 例如代码审查&quot;">​</a></h3><p>例如代码审查不需要修改代码的权限</p><h3 id="多任务并行处理-例如跑测试用例、分析错误日志、代码审查" tabindex="-1">多任务并行处理 - 例如跑测试用例、分析错误日志、代码审查 <a class="header-anchor" href="#多任务并行处理-例如跑测试用例、分析错误日志、代码审查" aria-label="Permalink to &quot;多任务并行处理 - 例如跑测试用例、分析错误日志、代码审查&quot;">​</a></h3><p>当需要同时处理多个任务时，使用子代理并行处理，最后将结果返回给主 Agent 进行整合。</p><h3 id="流水线任务-例如修复-bug" tabindex="-1">流水线任务 - 例如修复 bug <a class="header-anchor" href="#流水线任务-例如修复-bug" aria-label="Permalink to &quot;流水线任务 - 例如修复 bug&quot;">​</a></h3><p>例如修复 bug 可以拆成定位问题、分析问题、解决问题，验证问题 4个子任务，每个任务执行完后，才能执行下一个任务。</p><p>这类任务的关键在于每一个阶段的目标、权限和输出都是明确的，且下一个阶段依赖于上一个阶段的输出。</p><p><strong>如果需要用户频繁确认的任务，则不适合使用子代理。</strong></p><blockquote><p>‼️ 重要原则：子代理应该由主 Agent 创建，子代理不要创建新的子代理，</p></blockquote><h2 id="子代理的配置文件详解" tabindex="-1">子代理的配置文件详解 <a class="header-anchor" href="#子代理的配置文件详解" aria-label="Permalink to &quot;子代理的配置文件详解&quot;">​</a></h2><p>子代理文件一般位于 <code>.claude/subagents/</code> 目录下，是一个 Markdown 文件。</p><p>文件内容由以下几部分组成：</p><ul><li>YAML frontmatter 格式</li><li>Prompt 模版</li></ul><p>例如👇</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">---</span></span>
<span class="line"><span style="color:#e1e4e8;">name: code-reviewer</span></span>
<span class="line"><span style="color:#e1e4e8;">description: Review code for security issues and best practices. Use after code changes.</span></span>
<span class="line"><span style="color:#e1e4e8;">tools: Read, Grep, Glob</span></span>
<span class="line"><span style="color:#e1e4e8;">model: sonnet</span></span>
<span class="line"><span style="color:#e1e4e8;">---</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">你是一个代码审查专家。</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">当被调用时：</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">1. 首先理解代码变更的范围</span></span>
<span class="line"><span style="color:#e1e4e8;">2. 检查安全问题</span></span>
<span class="line"><span style="color:#e1e4e8;">3. 检查代码规范</span></span>
<span class="line"><span style="color:#e1e4e8;">4. 提供改进建议</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">输出格式：</span></span>
<span class="line"><span style="color:#e1e4e8;">## 审查结果</span></span>
<span class="line"><span style="color:#e1e4e8;">- 安全问题：[列表]</span></span>
<span class="line"><span style="color:#e1e4e8;">- 规范问题：[列表]</span></span>
<span class="line"><span style="color:#e1e4e8;">- 建议：[列表]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">---</span></span>
<span class="line"><span style="color:#24292e;">name: code-reviewer</span></span>
<span class="line"><span style="color:#24292e;">description: Review code for security issues and best practices. Use after code changes.</span></span>
<span class="line"><span style="color:#24292e;">tools: Read, Grep, Glob</span></span>
<span class="line"><span style="color:#24292e;">model: sonnet</span></span>
<span class="line"><span style="color:#24292e;">---</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">你是一个代码审查专家。</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">当被调用时：</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">1. 首先理解代码变更的范围</span></span>
<span class="line"><span style="color:#24292e;">2. 检查安全问题</span></span>
<span class="line"><span style="color:#24292e;">3. 检查代码规范</span></span>
<span class="line"><span style="color:#24292e;">4. 提供改进建议</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">输出格式：</span></span>
<span class="line"><span style="color:#24292e;">## 审查结果</span></span>
<span class="line"><span style="color:#24292e;">- 安全问题：[列表]</span></span>
<span class="line"><span style="color:#24292e;">- 规范问题：[列表]</span></span>
<span class="line"><span style="color:#24292e;">- 建议：[列表]</span></span></code></pre></div><p>YAML frontmatter 格式（--- 之间的内容）用于定义子代理的名称、职责、权限、上下文窗口等元数据。</p><p>Prompt 模版用于定义子代理的 Prompt，包括输入、输出、工具等。</p><h3 id="yaml-frontmatter-属性" tabindex="-1">YAML frontmatter 属性 <a class="header-anchor" href="#yaml-frontmatter-属性" aria-label="Permalink to &quot;YAML frontmatter 属性&quot;">​</a></h3><ul><li>name: 必填，子代理的名称，例如 <code>code-reviewer</code></li><li>description: 必填，子代理的描述，例如 <code>Review code for security issues and best practices. Use after code changes.</code></li><li>tools: 可选，工具白名单，例如 <code>Read, Grep, Glob</code></li><li>disallowedTools: 可选，工具黑名单，例如 <code>Write, Edit</code></li><li>model: 可选，模型名称，例如 <code>haiku / sonnet / opus / inherit</code></li><li>permissionMode: 可选，权限模式，例如 <code>default / plan / bypassPermissions</code></li><li>skills: 可选，技能列表，例如 <code>api-search / code-search</code></li><li>hooks: 可选，钩子列表，例如 <code>preToolUse</code></li></ul><p><img src="`+l+`" alt="YAML frontmatter 属性图"></p><p>接下来我们介绍几个关键的属性</p><h4 id="_1-description-描述" tabindex="-1">1. description 描述 <a class="header-anchor" href="#_1-description-描述" aria-label="Permalink to &quot;1. description 描述&quot;">​</a></h4><p>description 主要决定了 Claude 何时进行调用</p><p>好的 description 描述应该是具体的，而不是模糊的，例如套用模版 “怎么做” + “何时做” 进行描述</p><p>例如👇</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;"># 写的模糊</span></span>
<span class="line"><span style="color:#e1e4e8;">description: A code reviewer</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;"># 好的写法: 怎么做 + 何时做</span></span>
<span class="line"><span style="color:#e1e4e8;">description: Review code change for quality，security vulnerabilities，and best practices. Use proactively after code is modified or when user asks for code review.</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;"># 写的模糊</span></span>
<span class="line"><span style="color:#24292e;">description: A code reviewer</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;"># 好的写法: 怎么做 + 何时做</span></span>
<span class="line"><span style="color:#24292e;">description: Review code change for quality，security vulnerabilities，and best practices. Use proactively after code is modified or when user asks for code review.</span></span></code></pre></div><p>以代码 review 的 description 为例子，好的 description 应该包含 <em><strong>怎么做 CodeReview</strong></em> + <em><strong>何时做 CodeReview</strong></em></p><h4 id="_2-tools-vs-disallowedtools-白名单与黑名单" tabindex="-1">2. tools vs disallowedTools：白名单与黑名单 <a class="header-anchor" href="#_2-tools-vs-disallowedtools-白名单与黑名单" aria-label="Permalink to &quot;2. tools vs disallowedTools：白名单与黑名单&quot;">​</a></h4><p>还是以 CodeReview 为例子，在代码 review 的过程中，我们不需要 Claude Code 对代码进行修改，因此可以使用 disallowedTools: Write、Edit，禁用写、编辑工具。</p><p>而可以对文件进行读操作、文件查找、文件匹配，因此可以配置 Tools: Read、Grep、Glob</p><p>不要同时使用两者——选一种即可</p><h4 id="_3-model-模型选择与默认值" tabindex="-1">3. model：模型选择与默认值 <a class="header-anchor" href="#_3-model-模型选择与默认值" aria-label="Permalink to &quot;3. model：模型选择与默认值&quot;">​</a></h4><p>模型的选择具体看业务场景。</p><ul><li>如果是快速查找、没有复杂的业务逻辑，可以采用 haiku</li><li>如果是相对复杂的逻辑、代码分析，可以采用 sonnet</li><li>如果是研究型任务、复杂推理场景，可以采用 opus</li></ul><p>默认是跟随主窗口的模型</p><h4 id="_4-permissionmode-权限模式" tabindex="-1">4. permissionMode：权限模式 <a class="header-anchor" href="#_4-permissionmode-权限模式" aria-label="Permalink to &quot;4. permissionMode：权限模式&quot;">​</a></h4><p>permissionMode：权限模式</p><ul><li>default 模式，默认配置，适用于大部分场景</li><li>acceptEdits 模式，自动接受文件编辑，适用于修复类的场景</li><li>plan 模式，只读探索模式，适用于做规划、审查类的场景</li><li>dontAsk 模式，自动拒绝权限弹窗，适用于有严格权限控制的自动化场景</li><li>bypassPermissions: 跳过所有权限检查，适用于完全自动化场景</li></ul><p>例如子代理跑 code Review时，不能修改文件，那么可以给他配置</p><hr><h2 id="name-code-reviewertools-read-grep-glob-bashpermissionmode-plan-强制只读模式-即使有-bash-也无法写入" tabindex="-1">name: code-reviewer tools: Read, Grep, Glob, Bash permissionMode: plan # 强制只读模式，即使有 Bash 也无法写入 <a class="header-anchor" href="#name-code-reviewertools-read-grep-glob-bashpermissionmode-plan-强制只读模式-即使有-bash-也无法写入" aria-label="Permalink to &quot;name: code-reviewer
tools: Read, Grep, Glob, Bash
permissionMode: plan          # 强制只读模式，即使有 Bash 也无法写入&quot;">​</a></h2><h4 id="_5-skills-为子代理预加载知识" tabindex="-1">5. skills：为子代理预加载知识 <a class="header-anchor" href="#_5-skills-为子代理预加载知识" aria-label="Permalink to &quot;5. skills：为子代理预加载知识&quot;">​</a></h4><p>子代理可以通过 skills 字段预加载，例如👇</p><hr><p>name: impact-analyzer description: Analyze impact scope of code changes on the full call chain. tools: Read, Grep, Glob, Bash skills:</p><ul><li>chain-knowledge # 链路拓扑和 SLA 约束</li><li>recent-incidents # 近期事故记录</li></ul><hr><h4 id="_6-hooks-子代理专属的生命周期-hook" tabindex="-1">6. hooks：子代理专属的生命周期 Hook <a class="header-anchor" href="#_6-hooks-子代理专属的生命周期-hook" aria-label="Permalink to &quot;6. hooks：子代理专属的生命周期 Hook&quot;">​</a></h4><p>通过定义生命周期 hooks 可以对 Agent 进行更多个性化的管控，hooks 钩子具体可参考 <a href="https://code.claude.com/docs/zh-CN/hooks" target="_blank" rel="noreferrer">https://code.claude.com/docs/zh-CN/hooks</a></p><h2 id="举个例子" tabindex="-1">举个例子 <a class="header-anchor" href="#举个例子" aria-label="Permalink to &quot;举个例子&quot;">​</a></h2><h2 id="name-db-readerdescription-execute-read-only-database-queries-tools-bashhooks-pretooluse-matcher-bash-hooks-type-commandcommand-scripts-validate-readonly-query-sh" tabindex="-1">name: db-reader description: Execute read-only database queries. tools: Bash hooks: PreToolUse: - matcher: &quot;Bash&quot; hooks: - type: command command: &quot;./scripts/validate-readonly-query.sh&quot; <a class="header-anchor" href="#name-db-readerdescription-execute-read-only-database-queries-tools-bashhooks-pretooluse-matcher-bash-hooks-type-commandcommand-scripts-validate-readonly-query-sh" aria-label="Permalink to &quot;name: db-reader
description: Execute read-only database queries.
tools: Bash
hooks:
  PreToolUse:
    - matcher: &quot;Bash&quot;
      hooks:
        - type: command
          command: &quot;./scripts/validate-readonly-query.sh&quot;&quot;">​</a></h2><p>例如这个 db-reader 数据库查询子 Agent，每次在执行 Bash 命令查询数据库时，会触发 PreToolUse Hook 检查当前命令是否是 SELECT，只有 SELECT 才能通过。</p><p>这个比直接写在 Prompt 中更有约束力。</p><p>通过 hooks 我们发现子代理不仅可以控制有哪些工具，还可以控制工具能做什么操作，例如上面的例子中，我们控制了 Bash 命令只能执行 SELECT 操作。</p><p>当我们了解了 subAgent 强大的自控力后，我们可以在 上下文、权限、技能、钩子等等 基础上对 SubAgent 进行编排，让任务做的更快、更好。</p><h2 id="subagent-工作流编排" tabindex="-1">SubAgent 工作流编排 <a class="header-anchor" href="#subagent-工作流编排" aria-label="Permalink to &quot;SubAgent 工作流编排&quot;">​</a></h2><p>当我们了解了 subAgent 强大的自控力后，我们可以根据业务场景，对 SubAgent 进行编排，让任务完成地更加高效。</p><h2 id="并行场景-接手一个新的项目" tabindex="-1">并行场景: 接手一个新的项目 <a class="header-anchor" href="#并行场景-接手一个新的项目" aria-label="Permalink to &quot;并行场景: 接手一个新的项目&quot;">​</a></h2><p>例如一位前端同学转行做全栈，接手一个新的后端项目，需要快速了解项目代码，以往传统方式，需要人工对各个模块进行阅读，费时费力。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">1. 理解 Auth 模块代码 : 4 小时</span></span>
<span class="line"><span style="color:#e1e4e8;">2. 理解 DataBase 模块代码 : 8 小时</span></span>
<span class="line"><span style="color:#e1e4e8;">3. 理解 Api 模块代码 : 3 小时</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">综合理解: ?? （我记不起来了 😩）</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">1. 理解 Auth 模块代码 : 4 小时</span></span>
<span class="line"><span style="color:#24292e;">2. 理解 DataBase 模块代码 : 8 小时</span></span>
<span class="line"><span style="color:#24292e;">3. 理解 Api 模块代码 : 3 小时</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">综合理解: ?? （我记不起来了 😩）</span></span></code></pre></div><p>在 AI 时代下，我们可以通过 Agent 帮助我们理解代码，通过编排 SubAgent 并行处理，更加高效。例如👇</p><p><img src="`+o+'" alt="并行场景编排"></p><p>三个 SubAgent 并行处理，最后将结果返回给主 Agent 进行整合。</p><p><img src="'+p+'" alt="并行场景编排"></p><blockquote><p>并行探索的隐含前提：各子代理的探索任务之间不能有信息依赖</p></blockquote><h2 id="串行场景-修复-bug-流水线" tabindex="-1">串行场景: 修复 Bug 流水线 <a class="header-anchor" href="#串行场景-修复-bug-流水线" aria-label="Permalink to &quot;串行场景: 修复 Bug 流水线&quot;">​</a></h2><p>在修复 bug 过程中，我们会经历以下几个阶段：</p><ol><li>定位问题</li><li>分析问题</li><li>解决问题</li><li>验证问题</li></ol><p>基于此，我们可以将修复 bug 过程拆分成多个子任务，每个子任务由一个 SubAgent 完成。例如👇</p><p><img src="'+t+'" alt="串行场景编排"></p><p>四个 SubAgent 分别处理，每一个 SubAgent 的输出后，将结果返回给主 Agent 进行整合，主 Agent 再派发下一个 SubAgent 进行处理。</p><p>如果全部由主 Agent 处理，上下文膨胀，注意力分散，可能导致无法聚焦核心任务，从而影响任务完成效率。</p><p><img src="'+i+'" alt="串行场景编排"></p><h2 id="并行-vs-流水线-什么时候用什么模式" tabindex="-1">并行 vs 流水线：什么时候用什么模式 <a class="header-anchor" href="#并行-vs-流水线-什么时候用什么模式" aria-label="Permalink to &quot;并行 vs 流水线：什么时候用什么模式&quot;">​</a></h2><p>核心判断标准是：</p><ul><li>任务之间独立吗？→ 并行</li><li>任务之间有依赖吗？→ 流水线</li></ul><p><img src="'+r+'" alt="并行 vs 流水线"></p><p>在实际的业务场景中，可能并不是单纯的串行 或者 并行，可能是串行后有并行、并行后又串行等等，这种组合模式需要根据业务场景进行设计。</p><h2 id="subagent-team-团队协作" tabindex="-1">subAgent Team: 团队协作 <a class="header-anchor" href="#subagent-team-团队协作" aria-label="Permalink to &quot;subAgent Team: 团队协作&quot;">​</a></h2><p>聪明的同学可能已经发现了，在编排 SubAgent 时，因 SubAgent 之间无法直接通信，可能会遗漏一些关键信息，导致任务无法完成。</p><p>因此，我们可以通过 subAgent Team 来解决这个问题。</p><h3 id="案例" tabindex="-1">案例 <a class="header-anchor" href="#案例" aria-label="Permalink to &quot;案例&quot;">​</a></h3><p>你的系统出现了一个奇怪 bug——用户登录后偶尔会话丢失，没有明确的规律。你怀疑可能是：</p><ul><li>假设 A：JWT token 过期时间计算有问题</li><li>假设 B：Redis session 存储的竞态条件</li><li>假设 C：负载均衡器的 sticky session 配置</li></ul><p>如果用子代理，情况可能是这样。👇</p><p><img src="'+c+'" alt="subAgent Team"></p><p>如果子代理 B 能看到子代理 C 的发现，它可能会说：等等，Redis 连接数上限问题可能是因为 sticky session 5 分钟后切换了服务器，导致新的 Redis 连接被创建。这正是 Agent Teams 要解决的问题——让代理之间能够直接交流、互相挑战、协作推进。</p><p><img src="'+d+`" alt="subAgent Team"></p><h3 id="如何启用-subagent-team" tabindex="-1">如何启用 subAgent Team <a class="header-anchor" href="#如何启用-subagent-team" aria-label="Permalink to &quot;如何启用 subAgent Team&quot;">​</a></h3><p>Agent Teams 默认是关闭的，启用方式是在 settings.json 中设置环境变量：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">{</span></span>
<span class="line"><span style="color:#e1e4e8;">  &quot;env&quot;: {</span></span>
<span class="line"><span style="color:#e1e4e8;">    &quot;CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS&quot;: &quot;1&quot;</span></span>
<span class="line"><span style="color:#e1e4e8;">  }</span></span>
<span class="line"><span style="color:#e1e4e8;">}</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">{</span></span>
<span class="line"><span style="color:#24292e;">  &quot;env&quot;: {</span></span>
<span class="line"><span style="color:#24292e;">    &quot;CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS&quot;: &quot;1&quot;</span></span>
<span class="line"><span style="color:#24292e;">  }</span></span>
<span class="line"><span style="color:#24292e;">}</span></span></code></pre></div><p>启用后，用自然语言告诉 Claude 创建团队并描述任务：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">创建一个 agent team 从不同角度探索这个问题：</span></span>
<span class="line"><span style="color:#e1e4e8;">一个 teammate 负责 UX，一个负责技术架构（用最好的模型），一个扮演审评质疑者（用普通模型）。</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">创建一个 agent team 从不同角度探索这个问题：</span></span>
<span class="line"><span style="color:#24292e;">一个 teammate 负责 UX，一个负责技术架构（用最好的模型），一个扮演审评质疑者（用普通模型）。</span></span></code></pre></div><p>Claude 会建团队，生成指定的 Teammates 让它们探索问题，然后综合各方发现，完成后清理团队。团队成功创建后，一个 Agent Team 由以下组件构成:</p><p><img src="`+h+`" alt="subAgent Team 组成"></p><p>团队和任务相关的数据会存储在本地。</p><ul><li>团队配置：~/.claude/teams/{team-name}/config.json</li><li>任务列表：~/.claude/tasks/{team-name}/</li></ul><p>团队配置包含 members 数组，记录每个 Teammate 的名称、agent ID 和类型。Teammates 可以读取这个文件来发现其他团队成员。这些都是 Claude Code 自行搞定的，不需要我们操心去存放。</p><h2 id="从-subagents-到-multi-agent" tabindex="-1">从 SubAgents 到 Multi-Agent <a class="header-anchor" href="#从-subagents-到-multi-agent" aria-label="Permalink to &quot;从 SubAgents 到 Multi-Agent&quot;">​</a></h2><p>在 AI Agent 的工程实践中，有一个经典的误区——过早引入 <em><strong>多 Agent 架构</strong></em>，实际上，在大多数场景下，单一 Agent 已经足够应对需求，过早引入多 Agent 架构反而会引入复杂度，导致团队协作成本上升。</p><p>只有当系统确实触及单 Agent 的架构边界时， 才考虑采用多 Agent 的设计模式。</p><p>那什么时候需要引入多 Agent 架构呢？</p><h3 id="两个核心触发条件" tabindex="-1">两个核心触发条件 <a class="header-anchor" href="#两个核心触发条件" aria-label="Permalink to &quot;两个核心触发条件&quot;">​</a></h3><h4 id="_1-上下文管理挑战" tabindex="-1">1. 上下文管理挑战 <a class="header-anchor" href="#_1-上下文管理挑战" aria-label="Permalink to &quot;1. 上下文管理挑战&quot;">​</a></h4><p>多个领域的上下文知识无法舒适地填充到单一的 Prompt 中，<strong>需要策略性地分发上下文</strong>, 而不是堆在一起，导致上下文膨胀，稀释 Agent 注意力。</p><h4 id="_2-分布式开发需求" tabindex="-1">2. 分布式开发需求 <a class="header-anchor" href="#_2-分布式开发需求" aria-label="Permalink to &quot;2. 分布式开发需求&quot;">​</a></h4><p>当多个团队需要独立拥有和维护各自的 Agent 能力时。比如安全团队维护审计 Agent，测试团队维护测试 Agent，开发团队维护开发 Agent，各团队可以独立迭代而不互相干扰，此时需要跨越单 Agent 的能力边界时，需要引入多 Agent 架构。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">单 Agent 的困境：</span></span>
<span class="line"><span style="color:#e1e4e8;">┌─────────────────────────────────────────────────┐</span></span>
<span class="line"><span style="color:#e1e4e8;">│ System Prompt:                                  │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你是代码专家（200行指令）                       │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你也是测试专家（150行指令）                     │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你还是安全审计专家（180行指令）                  │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   - 你同时是文档撰写专家（100行指令）                │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   ...                                           │</span></span>
<span class="line"><span style="color:#e1e4e8;">│   Token 爆炸，模型注意力分散                       │</span></span>
<span class="line"><span style="color:#e1e4e8;">└─────────────────────────────────────────────────┘</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">单 Agent 的困境：</span></span>
<span class="line"><span style="color:#24292e;">┌─────────────────────────────────────────────────┐</span></span>
<span class="line"><span style="color:#24292e;">│ System Prompt:                                  │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你是代码专家（200行指令）                       │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你也是测试专家（150行指令）                     │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你还是安全审计专家（180行指令）                  │</span></span>
<span class="line"><span style="color:#24292e;">│   - 你同时是文档撰写专家（100行指令）                │</span></span>
<span class="line"><span style="color:#24292e;">│   ...                                           │</span></span>
<span class="line"><span style="color:#24292e;">│   Token 爆炸，模型注意力分散                       │</span></span>
<span class="line"><span style="color:#24292e;">└─────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="multi-agent-的架构演进路径" tabindex="-1">Multi-Agent 的架构演进路径 <a class="header-anchor" href="#multi-agent-的架构演进路径" aria-label="Permalink to &quot;Multi-Agent 的架构演进路径&quot;">​</a></h3><h4 id="_1-单一-agent-架构" tabindex="-1">1. 单一 Agent 架构 <a class="header-anchor" href="#_1-单一-agent-架构" aria-label="Permalink to &quot;1. 单一 Agent 架构&quot;">​</a></h4><p>适合前期大多数简单的场景，一开始没必要引入多 Agent 架构。</p><p><img src="`+u+'" alt="单一 Agent 架构"></p><h4 id="_2-单-agent-skills" tabindex="-1">2. 单 Agent + Skills <a class="header-anchor" href="#_2-单-agent-skills" aria-label="Permalink to &quot;2. 单 Agent + Skills&quot;">​</a></h4><p>随着业务发展，Tools 越来越多、Prompt 越来越膨胀时，可以使用 SKILL 做渐进式加载，避免一次性加载太多，导致模型注意力分散。</p><p><img src="'+g+'" alt="单 Agent + Skills 架构"></p><h4 id="_3-supervisor-多个子-agent" tabindex="-1">3. Supervisor + 多个子 Agent <a class="header-anchor" href="#_3-supervisor-多个子-agent" aria-label="Permalink to &quot;3. Supervisor + 多个子 Agent&quot;">​</a></h4><p>当业务变得复杂，需要做不同领域的知识、上下文隔离、权限控制等等时，采用 Supervisor + 多个子 Agent 架构。</p><p><img src="'+b+'" alt="Supervisor + 多个子 Agent 架构"></p><h4 id="_4-混合架构" tabindex="-1">4. 混合架构 <a class="header-anchor" href="#_4-混合架构" aria-label="Permalink to &quot;4. 混合架构&quot;">​</a></h4><p>成熟系统中，不同类型的任务流可能采用不同的模式。Router 处理分类，Sub-Agent 处理并行研究，Handoff 处理顺序流程。</p><p><img src="'+m+`" alt="混合架构"></p><h3 id="如何决策是否应该引入多-agent-架构" tabindex="-1">如何决策是否应该引入多 Agent 架构 <a class="header-anchor" href="#如何决策是否应该引入多-agent-架构" aria-label="Permalink to &quot;如何决策是否应该引入多 Agent 架构&quot;">​</a></h3><p>当系统确实触及单 Agent 的架构边界时， 才考虑采用多 Agent 的设计模式。可以参考下图进行决策：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">你的任务需要多 Agent 吗？</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 单一领域、工具 &lt; 5 个、上下文 &lt; 50K tokens</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 不需要。用单 Agent + 好的 prompt 即可</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 单一领域、但工具 &gt; 10 个</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 考虑 Skills 模式（渐进式能力加载）</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 多领域、各领域需要独立上下文</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 使用 Sub-Agents 模式</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">├─ 需要多步骤状态流转（如客服工单流程）</span></span>
<span class="line"><span style="color:#e1e4e8;">│  └─→ 使用 Handoffs 模式</span></span>
<span class="line"><span style="color:#e1e4e8;">│</span></span>
<span class="line"><span style="color:#e1e4e8;">└─ 需要跨多个数据源并行查询</span></span>
<span class="line"><span style="color:#e1e4e8;">   └─→ 使用 Router 模式</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">你的任务需要多 Agent 吗？</span></span>
<span class="line"><span style="color:#24292e;">├─ 单一领域、工具 &lt; 5 个、上下文 &lt; 50K tokens</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 不需要。用单 Agent + 好的 prompt 即可</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">├─ 单一领域、但工具 &gt; 10 个</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 考虑 Skills 模式（渐进式能力加载）</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">├─ 多领域、各领域需要独立上下文</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 使用 Sub-Agents 模式</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">├─ 需要多步骤状态流转（如客服工单流程）</span></span>
<span class="line"><span style="color:#24292e;">│  └─→ 使用 Handoffs 模式</span></span>
<span class="line"><span style="color:#24292e;">│</span></span>
<span class="line"><span style="color:#24292e;">└─ 需要跨多个数据源并行查询</span></span>
<span class="line"><span style="color:#24292e;">   └─→ 使用 Router 模式</span></span></code></pre></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>如今市面上会有很多创建 SubAgent 的工具，SKILL 也好模版也好，但如何判断这个 SubAgent 是否好，不仅需要有大量的实践经验，也需要有我们对 SubAgent有体系化的认知，有自己的判断标准。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://code.claude.com/docs/zh-CN/sub-agents" target="_blank" rel="noreferrer">SubAgent 官方文档</a></li><li><a href="https://www.anthropic.com/engineering/effective-context-engineering-for-ai-agents" target="_blank" rel="noreferrer">Effective context engineering for AI agents</a></li><li><a href="https://www.anthropic.com/engineering/multi-agent-architecture-in-ai-agent-engineering" target="_blank" rel="noreferrer">Multi-Agent Architecture in AI Agent Engineering</a></li><li><a href="https://code.claude.com/docs/zh-CN/agent-teams" target="_blank" rel="noreferrer">SubAgent Team</a></li></ul>`,155),k=[A];function q(v,f,_,P,C,S){return s(),a("div",null,k)}const T=e(y,[["render",q]]);export{w as __pageData,T as default};
